import * as React from "react";
import { StyleSheet, View, Text } from "react-native";
import Animated, {
	FadeIn,
	FadeOut,
	SlideInDown,
	SlideOutDown,
} from "react-native-reanimated";
import { cn } from "{{UTILS_ALIAS}}";

// A simple universal Drawer implementation using Reanimated
// In the future, this can be swapped with a more complex primitive if needed

const DrawerContext = React.createContext<{
	open: boolean;
	setOpen: (open: boolean) => void;
}>({
	open: false,
	setOpen: () => {},
});

const Drawer = ({
	children,
	open: controlledOpen,
	onOpenChange,
}: {
	children: React.ReactNode;
	open?: boolean;
	onOpenChange?: (open: boolean) => void;
}) => {
	const [internalOpen, setInternalOpen] = React.useState(false);
	const open = controlledOpen !== undefined ? controlledOpen : internalOpen;
	const setOpen = onOpenChange || setInternalOpen;

	return (
		<DrawerContext.Provider value={{ open, setOpen }}>
			{children}
		</DrawerContext.Provider>
	);
};

const DrawerTrigger = ({
	asChild,
	children,
	...props
}: {
	asChild?: boolean;
	children: React.ReactNode;
}) => {
	const { setOpen } = React.useContext(DrawerContext);

	if (asChild && React.isValidElement(children)) {
		return React.cloneElement(children as React.ReactElement<any>, {
			onPress: () => setOpen(true),
			...props,
		});
	}

	return (
		<View {...props} onTouchEnd={() => setOpen(true)}>
			{children}
		</View>
	);
};

const DrawerContent = ({
	children,
	className,
}: {
	children: React.ReactNode;
	className?: string;
}) => {
	const { open, setOpen } = React.useContext(DrawerContext);

	if (!open) return null;

	return (
		<View style={StyleSheet.absoluteFill} className="z-50">
			<Animated.View
				entering={FadeIn}
				exiting={FadeOut}
				className="absolute inset-0 bg-black/40"
				onTouchEnd={() => setOpen(false)}
			/>
			<Animated.View
				entering={SlideInDown}
				exiting={SlideOutDown}
				className={cn(
					"absolute bottom-0 left-0 right-0 bg-white dark:bg-slate-900 p-6 rounded-t-3xl min-h-[300px]",
					className,
				)}
			>
				<View className="w-12 h-1.5 bg-slate-200 dark:bg-slate-800 rounded-full mx-auto mb-6" />
				{children}
			</Animated.View>
		</View>
	);
};

const DrawerHeader = ({
	className,
	children,
}: {
	className?: string;
	children: React.ReactNode;
}) => (
	<View className={cn("mb-4 space-y-2", className)}>
		{typeof children === 'string' ? <Text>{children}</Text> : children}
	</View>
);

const DrawerTitle = ({
	className,
	children,
}: {
	className?: string;
	children: React.ReactNode;
}) => (
	<Text
		className={cn(
			"text-xl font-semibold text-slate-900 dark:text-slate-50",
			className,
		)}
	>
		{typeof children === 'string' ? <Text>{children}</Text> : children}
	</Text>
);

const DrawerDescription = ({
	className,
	children,
}: {
	className?: string;
	children: React.ReactNode;
}) => (
	<Text className={cn("text-sm text-slate-500 dark:text-slate-400", className)}>
		{typeof children === 'string' ? <Text>{children}</Text> : children}
	</Text>
);

const DrawerFooter = ({
	className,
	children,
}: {
	className?: string;
	children: React.ReactNode;
}) => <View className={cn("mt-auto pt-4 space-y-2", className)}>{children}</View>;

export {
	Drawer,
	DrawerTrigger,
	DrawerContent,
	DrawerHeader,
	DrawerTitle,
	DrawerDescription,
	DrawerFooter,
};
